                        }
                        else
                        {
                            context.EvaluatedKeywordForProperty(true, 0, RequiredPropertyAlgPresent, "alg"u8, "required"u8);
                        }

                        if ((requiredPropertyChildHandler_seenItems[RequiredOffsetForKeysToSign] & RequiredBitForKeysToSign) == 0)
                        {
                            context.EvaluatedKeywordForProperty(false, 1, RequiredPropertyKeysToSignNotPresent, "keys_to_sign"u8, "required"u8);
                        }
                        else
                        {
                            context.EvaluatedKeywordForProperty(true, 1, RequiredPropertyKeysToSignPresent, "keys_to_sign"u8, "required"u8);
                        }

                        if ((requiredPropertyChildHandler_seenItems[RequiredOffsetForKid] & RequiredBitForKid) == 0)
                        {
                            context.EvaluatedKeywordForProperty(false, 2, RequiredPropertyKidNotPresent, "kid"u8, "required"u8);
                        }
                        else
                        {
                            context.EvaluatedKeywordForProperty(true, 2, RequiredPropertyKidPresent, "kid"u8, "required"u8);
                        }
                    }
                }
            }

            internal static bool Evaluate(
                IJsonDocument parentDocument,
                int parentIndex,
                IJsonSchemaResultsCollector? resultsCollector = null)
            {
                JsonSchemaContext context = JsonSchemaContext.BeginContext(
                parentDocument,
                parentIndex,
                usingEvaluatedItems: false,
                usingEvaluatedProperties: true,
                resultsCollector: resultsCollector);

                try
                {
                    Evaluate(parentDocument, parentIndex, ref context);
                    context.EndContext();
                    return context.IsMatch;
                }
                finally
                {
                    context.Dispose();
                }
            }

